INSERT INTO `v1_026e5b95fc1a2aad454f3bcf77a61bafb6199d18ea0c41e08d78a17d68ccb287` VALUES (1, 3000, 2, "vo_minigame_1013_icon_2_002_001", 2, 2, "訓練はまだ\nここからですわ", 1000, "vo_minigame_1013_icon_1_002_001", "調子が上がって\nきたなっ");
INSERT INTO `v1_026e5b95fc1a2aad454f3bcf77a61bafb6199d18ea0c41e08d78a17d68ccb287` VALUES (2, 3000, 2, "vo_minigame_1013_icon_2_003_001", 2, 2, "クスクス、悪くない\n流れですわね", 5000, "vo_minigame_1013_icon_1_003_001", "ほらほら、\nまだいけるだろ？");
INSERT INTO `v1_026e5b95fc1a2aad454f3bcf77a61bafb6199d18ea0c41e08d78a17d68ccb287` VALUES (3, 3000, 2, "vo_minigame_1013_icon_2_004_001", 2, 3, "すばらしい\n記録ですわ", 10000, "vo_minigame_1013_icon_1_004_001", "へへっ、おまえら\nやるじゃねえか！");
INSERT INTO `v1_026e5b95fc1a2aad454f3bcf77a61bafb6199d18ea0c41e08d78a17d68ccb287` VALUES (4, 3000, 3, "vo_minigame_1013_icon_2_005_001", 2, 3, "乗りに乗って\nいますわね", 10000, "vo_minigame_1013_icon_1_005_001", "あたしたちはまだ\n止まらねえぜ！");
INSERT INTO `v1_026e5b95fc1a2aad454f3bcf77a61bafb6199d18ea0c41e08d78a17d68ccb287` VALUES (5, 3000, 3, "vo_minigame_1013_icon_2_005_002", 2, 3, "まだまだ行きます\nついてきなさい", 10000, "vo_minigame_1013_icon_1_005_002", "見てろよ！\nマコト班の快進撃だ！");
INSERT INTO `v1_026e5b95fc1a2aad454f3bcf77a61bafb6199d18ea0c41e08d78a17d68ccb287` VALUES (6, 3000, 3, "vo_minigame_1013_icon_2_005_003", 2, 3, "エリコ班の\n本領発揮ですわ！", 10000, "vo_minigame_1013_icon_1_005_003", "うおぉぉっ！\n絶好調だぜ！");
INSERT INTO `v1_026e5b95fc1a2aad454f3bcf77a61bafb6199d18ea0c41e08d78a17d68ccb287` VALUES (7, 3000, 4, "vo_minigame_1013_icon_2_006_001", 2, 3, "ここからは\n前人未到の領域です！", 0, "vo_minigame_1013_icon_1_006_001", "どこまで行けるか\n楽しみだなっ！");
INSERT INTO `v1_026e5b95fc1a2aad454f3bcf77a61bafb6199d18ea0c41e08d78a17d68ccb287` VALUES (8, 1000, 5, "vo_minigame_1013_icon_2_007_001", 3, 4, "厄介でしたわ…", 1, "vo_minigame_1013_icon_1_007_001", "まだ諦めんなよっ");
INSERT INTO `v1_026e5b95fc1a2aad454f3bcf77a61bafb6199d18ea0c41e08d78a17d68ccb287` VALUES (9, 1000, 5, "vo_minigame_1013_icon_2_007_002", 3, 4, "油断大敵です", 1, "vo_minigame_1013_icon_1_007_002", "冷やっとしたぜ…！");
INSERT INTO `v1_026e5b95fc1a2aad454f3bcf77a61bafb6199d18ea0c41e08d78a17d68ccb287` VALUES (10, 1000, 5, "vo_minigame_1013_icon_2_007_003", 3, 4, "忌々しいっ…", 1, "vo_minigame_1013_icon_1_007_003", "弱音を吐くなっ");
INSERT INTO `v1_026e5b95fc1a2aad454f3bcf77a61bafb6199d18ea0c41e08d78a17d68ccb287` VALUES (11, 1500, 6, "vo_minigame_1013_icon_2_008_001", 4, 3, "大所帯ですわね", 99, "vo_minigame_1013_icon_1_008_001", "マコト班集合！");
INSERT INTO `v1_026e5b95fc1a2aad454f3bcf77a61bafb6199d18ea0c41e08d78a17d68ccb287` VALUES (12, 1500, 6, "vo_minigame_1013_icon_2_008_002", 4, 3, "エリコ班へようこそ", 99, "vo_minigame_1013_icon_1_008_002", "連携してくぞ！");
INSERT INTO `v1_026e5b95fc1a2aad454f3bcf77a61bafb6199d18ea0c41e08d78a17d68ccb287` VALUES (13, 3000, 8, "vo_minigame_1013_icon_2_020_001", 1, 6, "ナナカちゃんに\nお任せあれ", 0, "vo_minigame_1013_icon_1_020_001", "みんなに力を！");
INSERT INTO `v1_026e5b95fc1a2aad454f3bcf77a61bafb6199d18ea0c41e08d78a17d68ccb287` VALUES (14, 3000, 9, "vo_minigame_1013_icon_2_022_001", 1, 7, "はっはっは！\n任せろ！", 0, "vo_minigame_1013_icon_1_022_001", "任せてくれたまえ");
INSERT INTO `v1_026e5b95fc1a2aad454f3bcf77a61bafb6199d18ea0c41e08d78a17d68ccb287` VALUES (15, 3000, 10, "vo_minigame_1013_icon_2_023_001", 1, 8, "どんどんいくわよ", 0, "vo_minigame_1013_icon_1_023_001", "ほな、いきまひょか");
